from itertools import product

class Encrypter:
    def __init__(self, keys, values, dictionary):
        self.keys = keys
        self.values = values
        self.dictionary = set(dictionary)

    def encrypt(self, word1):
        result = []
        for c in word1:
            if c not in self.keys:
                return ''
            i = self.keys.index(c)
            result.append(self.values[i])
        return ''.join(result)

    def decrypt(self, word2):
        chunks = [word2[i:i + 2] for i in range(0, len(word2), 2)]
        options = []
        for ch in chunks:
            matches = [self.keys[i] for i in range(len(self.values)) if self.values[i] == ch]
            if not matches:
                return 0
            options.append(matches)
        count = 0
        for combo in product(*options):
            if ''.join(combo) in self.dictionary:
                count += 1
        return count

