class Encrypter:
    def __init__(self, keys, values, dictionary):
        self.enc_map = {k: v for k, v in zip(keys, values)}
        self.count = {}
        for word in dictionary:
            enc = self._encrypt_or_none(word)
            if enc is not None:
                self.count[enc] = self.count.get(enc, 0) + 1

    def _encrypt_or_none(self, word):
        parts = []
        for c in word:
            if c not in self.enc_map:
                return None
            parts.append(self.enc_map[c])
        return ''.join(parts)

    def encrypt(self, word1):
        result = self._encrypt_or_none(word1)
        return result if result is not None else ''

    def decrypt(self, word2):
        return self.count.get(word2, 0)

