class Encrypter {
    constructor(keys, values, dictionary) {
        this.encMap = new Map();
        for (let i = 0; i < keys.length; i++) this.encMap.set(keys[i], values[i]);
        this.count = new Map();
        for (const word of dictionary) {
            const enc = this._encryptOrNull(word);
            if (enc !== null) this.count.set(enc, (this.count.get(enc) || 0) + 1);
        }
    }

    _encryptOrNull(word) {
        let out = '';
        for (const c of word) {
            if (!this.encMap.has(c)) return null;
            out += this.encMap.get(c);
        }
        return out;
    }

    encrypt(word1) {
        const r = this._encryptOrNull(word1);
        return r === null ? '' : r;
    }

    decrypt(word2) {
        return this.count.get(word2) || 0;
    }
}
